SELECT COUNT(award_id) AS award_count
FROM awards
WHERE recipient_id = 1 AND season_id = 1;

SELECT CAST(COUNT(*) AS REAL) / COUNT(DISTINCT user_id) AS avg_accesses_per_user
FROM access_logs
WHERE season_id = 1;

SELECT COUNT(*) AS total_awards
FROM awards
WHERE recipient_id = (SELECT team_id FROM teams WHERE team_name = 'Golden State Warriors');

SELECT AVG(games_missed) AS average_games_missed
FROM injuries
WHERE team_id = 1 AND season_id = 1;

SELECT COUNT(*) AS total_games_played
FROM game_logs
WHERE team_id = 1 AND season_id = 1;

SELECT COUNT(DISTINCT recipient_id) AS NumberOfTeamsWithChampionships
FROM awards
WHERE award_name = 'Champions' AND recipient_type = 'Team';
